features.snippet:
input [1:0] select;
output reg [1:0] result;
always @(posedge clk) begin
  case (select)
    2'b00: result <= 2'b11;
    2'b01: result <= 2'b10;
    2'b10: result <= 2'b01;
    default: result <= 2'b00;
  endcase
end

input [2:0] sel;
output reg [7:0] out;
always @* begin
  casex (sel)
    3'b00?: out = 8'h01;
    3'b01?: out = 8'h02;
    3'b1??: out = 8'h04;
  endcase
end
